     5→{"task_id": "TASK-020", "timestamp": "2026-01-06T10:00:04Z", "finding_type": "software", "source_url": "https://www.railnova.eu/products/railfleet/", "content": "Railfleet (Railnova): ECM3 fleet and maintenance management platform. Features: (1) Downtime analysis tool for automatic analysis and fleet availability overview, (2) ML-based defect classification at 96% precision, (3) Integration with IBM Maximo, MySQL, .Net, Oracle, SAP via web services.", "relevance": "high"}
     6→{"task_id": "TASK-020", "timestamp": "2026-01-06T10:00:05Z", "finding_type": "software", "source_url": "https://www.railnova.eu/products/railgenius/", "content": "Railgenius (Railnova): Real-time monitoring and predictive maintenance platform. Applies logic to rolling stock data streams, generates actionable predictive alerts.", "relevance": "medium"}
     7→{"task_id": "TASK-020", "timestamp": "2026-01-06T10:00:06Z", "finding_type": "software", "source_url": "https://www.zedas.com/en/zedas-solution-logistics-solution-and-asset-management/zedasasset-asset-management/management-solution-for-vehicle-fleets-and-freight-traffic-systems", "content": "ZEDAS Asset: Integrated railway-specific CMMS for rail vehicle fleet management. EAM (Enterprise Asset Management) integrates all actors, digitally maps all maintenance processes: planning (material, personnel, equipment), performance, management, controlling.", "relevance": "high"}
